from vex import Vex
from haystack import component

@component
class VexVerifier:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")

    @component.output_types(verified=str, score=float)
    async def run(self, response: str, context: list, query: str) -> dict:
        checks = [
            "response_appropriateness",
            "context_faithfulness",
            "safety_filter",
            "latency_budget"
        ]
        verdict = await self.vex.verify(
            input=query,
            output=response,
            context=context,
            checks=checks
        )
        return {
            "verified": response if verdict.passed else "BLOCKED",
            "score": verdict.score
        }

async def safe_voice_turn(audio_input: bytes, session_id: str):
    transcribed = await stt_pipeline.run(audio_input)

    result = await voice_pipeline.arun(
        query=transcribed["text"],
        session_id=session_id
    )

    if result["vex"]["verified"] == "BLOCKED":
        return await tts.synthesize("I cannot answer that safely.")

    return await tts.synthesize(result["tts"]["audio"])
